const fs = require("fs");
const axios = require("axios");

const transcript = fs.readFileSync(
  "/dataset/onboarding_calls/transcript.txt",
  "utf8"
);

const prompt = `
You are updating an existing system configuration.

Extract ONLY updated fields from the onboarding transcript.

Return JSON patch.

Rules:
- Only include fields mentioned in transcript
- Do NOT include fields that are unchanged
- Do NOT guess missing values

Possible fields:
business_hours
emergency_definition
emergency_routing_rules
call_transfer_rules
integration_constraints
office_address

Transcript:
${transcript}
`;

const response = await axios.post(
  "http://host.docker.internal:11434/api/generate",
  {
    model: "llama3",
    prompt: prompt,
    stream: false
  }
);

return [
  {
    json: {
      update_patch: response.data.response
    }
  }
];

const fs = require("fs");

const patch = items[0].json.patch;

const accountId = "transcript";

const v1Path = `/outputs/accounts/${accountId}/v1/memo.json`;

const v1 = JSON.parse(
  fs.readFileSync(v1Path,"utf8")
);

// merge
const v2 = {
  ...v1,
  ...patch
};

const v2Dir = `/outputs/accounts/${accountId}/v2`;

fs.mkdirSync(v2Dir,{recursive:true});

fs.writeFileSync(
  `${v2Dir}/memo.json`,
  JSON.stringify(v2,null,2)
);

return [
 {
   json:{
     v1:v1,
     v2:v2,
     accountId:accountId
   }
 }
];

const fs = require("fs");

const v1 = items[0].json.v1;
const v2 = items[0].json.v2;
const accountId = items[0].json.accountId;

const changes = [];

for (const key in v2) {

 if (JSON.stringify(v1[key]) !== JSON.stringify(v2[key])) {

   changes.push({
     field:key,
     previous:v1[key],
     updated:v2[key]
   });

 }

}

fs.writeFileSync(
  `/outputs/accounts/${accountId}/changes.json`,
  JSON.stringify(changes,null,2)
);

return [{json:{changes}}];

